import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Site {
  id: string;
  title: string;
  url: string;
  description: string;
  category: Category;
  tags: string[];
  yearEstablished?: string;
  curatorNote?: string;
}

export enum Category {
  ALL = 'All',
  INTERACTIVE_ART = 'Interactive Art',
  USELESS_WEB = 'The Useless Web',
  EDUCATIONAL = 'Educational',
  RETRO = 'Retro/Nostalgia',
  TOOLS = 'Niche Tools',
  MYSTERY = 'Mystery',
  MUSIC = 'Music/Audio',
}

export type FetchStatus = 'idle' | 'loading' | 'success' | 'error';

import { GoogleGenAI, Type } from "@google/genai";
import { Site, Category } from '../types';
import { v4 as uuidv4 } from 'uuid';

const apiKey = process.env.API_KEY || '';

// Initialize client ONLY if key exists to avoid immediate crash, though strict mode requires it.
const ai = apiKey ? new GoogleGenAI({ apiKey }) : null;

export const fetchRecommendations = async (category: Category, count: number = 3): Promise<Site[]> => {
  if (!ai) {
    console.warn("No API Key found. Returning empty list.");
    return [];
  }

  const categoryPrompt = category === Category.ALL 
    ? "any category, but focus on the weird, obscure, wonderful, and useless web." 
    : `the category '${category}'.`;

  const prompt = `
    I need a list of ${count} REAL, EXISTING, and OBSCURE websites. 
    Focus on ${categoryPrompt}

    CRITICAL RULES:
    1. The websites MUST be real and currently online.
    2. Do NOT invent fake URLs.
    3. Focus on "The Useless Web", "Neocities" gems, "Net Art", niche museums, interactive experiments, or unique single-serving sites.
    4. Avoid mainstream social media or standard corporate sites.
    5. Avoid AI-generated content farms.

    Return a valid JSON array of objects.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              url: { type: Type.STRING },
              description: { type: Type.STRING },
              category: { type: Type.STRING, description: "Match one of: Interactive Art, The Useless Web, Educational, Retro/Nostalgia, Niche Tools, Mystery, Music/Audio" },
              tags: { type: Type.ARRAY, items: { type: Type.STRING } },
              yearEstablished: { type: Type.STRING, description: "Approximate year or 'Unknown'" },
              curatorNote: { type: Type.STRING, description: "A witty or intriguing reason to visit this site." }
            },
            required: ['title', 'url', 'description', 'category', 'tags']
          }
        }
      }
    });

    const rawText = response.text;
    if (!rawText) return [];

    const parsedData = JSON.parse(rawText);

    // Map to our Site interface and ensure IDs
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const sites: Site[] = parsedData.map((item: any) => ({
      ...item,
      id: uuidv4(), // Generate a temp ID for React keys
      // Normalize category if Gemini returns something slightly off
      category: Object.values(Category).includes(item.category) ? item.category : Category.MYSTERY
    }));

    return sites;

  } catch (error) {
    console.error("Gemini discovery failed:", error);
    return [];
  }
};

