import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Rabbit, History, Sparkles, AlertCircle, RefreshCw, Menu, X, ExternalLink, Github } from 'lucide-react';
import { Site, Category, FetchStatus } from './types';
import { INITIAL_SITES, CATEGORY_COLORS } from './constants';
import { fetchRecommendations } from './services/geminiService';
import { SiteCard } from './components/SiteCard';

// Hook for local storage
function useLocalStorage<T>(key: string, initialValue: T): [T, (value: T) => void] {
  const [storedValue, setStoredValue] = useState<T>(() => {
    try {
      const item = window.localStorage.getItem(key);
      return item ? JSON.parse(item) : initialValue;
    } catch (error) {
      console.error(error);
      return initialValue;
    }
  });

  const setValue = (value: T) => {
    try {
      setStoredValue(value);
      window.localStorage.setItem(key, JSON.stringify(value));
    } catch (error) {
      console.error(error);
    }
  };

  return [storedValue, setValue];
}

const App: React.FC = () => {
  // State
  const [currentSite, setCurrentSite] = useState<Site | null>(null);
  const [status, setStatus] = useState<FetchStatus>('idle');
  const [selectedCategory, setSelectedCategory] = useState<Category>(Category.ALL);
