  // though basic logic handles it.

  const addToHistory = (site: Site) => {
    setHistory(prev => {
      // Avoid duplicates at the top of the stack
      if (prev.length > 0 && prev[0].id === site.id) return prev;
      return [site, ...prev].slice(0, 50); // Keep last 50
    });
  };

  const toggleFavorite = (site: Site) => {
    setFavorites(prev => {
      const exists = prev.find(s => s.id === site.id);
      if (exists) {
        return prev.filter(s => s.id !== site.id);
      }
      return [site, ...prev];
    });
  };

  // The core stumbling logic
  const handleStumble = useCallback(async () => {
    setStatus('loading');
    setShowWelcome(false);

    // 1. Check Queue first
    if (siteQueue.length > 0) {
      const nextSite = siteQueue[0];
      setSiteQueue(prev => prev.slice(1));
      setCurrentSite(nextSite);
      addToHistory(nextSite);
      setStatus('success');

      // If queue is getting low, fetch more in background
      if (siteQueue.length < 3) {
        fetchMoreSites(selectedCategory);
      }
      return;
    }

    // 2. If Queue empty, fetch new
    try {
      // Try fetching from API
      const newSites = await fetchRecommendations(selectedCategory);

      if (newSites.length > 0) {
        const first = newSites[0];
        const rest = newSites.slice(1);

        setCurrentSite(first);
        addToHistory(first);
        setSiteQueue(rest);
        setStatus('success');
      } else {
        // Fallback to local data if API fails or returns nothing
        fallbackStumble();
      }
    } catch (e) {
      console.error(e);
      fallbackStumble();
    }
  }, [selectedCategory, siteQueue]); // Removed 'history' and 'addToHistory' from deps to avoid loop complexity, using functional updates inside.

  const fallbackStumble = () => {
    // Pick random from INITIAL_SITES that isn't the current one
    const available = INITIAL_SITES.filter(s => 
      selectedCategory === Category.ALL || s.category === selectedCategory
    );

    if (available.length === 0) {
      // If filtering is too strict and we have no local data, fallback to ALL
      const anySite = INITIAL_SITES[Math.floor(Math.random() * INITIAL_SITES.length)];
      setCurrentSite(anySite);
      addToHistory(anySite);
      setStatus('success');
      return;
    }

    const random = available[Math.floor(Math.random() * available.length)];
    setCurrentSite(random);
    addToHistory(random);
    setStatus('success');
  };

  const fetchMoreSites = async (category: Category) => {
    try {
      const newSites = await fetchRecommendations(category, 3);
      setSiteQueue(prev => [...prev, ...newSites]);
    } catch (e) {
      console.warn("Background fetch failed", e);
    }
  };

  // Reset queue when category changes
  useEffect(() => {
    setSiteQueue([]);
  }, [selectedCategory]);

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 font-sans selection:bg-indigo-500 selection:text-white flex flex-col">

      {/* Header */}
      <header className="sticky top-0 z-40 w-full border-b border-slate-800 bg-slate-950/80 backdrop-blur-md">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setShowWelcome(true)}>
            <div className="bg-indigo-600 p-2 rounded-lg">
              <Rabbit className="text-white" size={24} />
            </div>
            <span className="font-display font-bold text-xl tracking-tight text-white hidden sm:block">
              Rabbit<span className="text-indigo-400">Hole</span>
            </span>
          </div>

          <div className="flex items-center gap-4">
            <div className="hidden md:flex items-center gap-2 bg-slate-900 p-1 rounded-lg border border-slate-800">
               <select 
                  value={selectedCategory}
                  onChange={(e) => setSelectedCategory(e.target.value as Category)}
                  className="bg-transparent text-sm font-medium text-slate-300 px-3 py-1.5 rounded-md focus:outline-none focus:bg-slate-800 cursor-pointer"
               >
                 {Object.values(Category).map(cat => (
                   <option key={cat} value={cat}>{cat}</option>
                 ))}
               </select>
            </div>

            <button 
              onClick={() => setIsSidebarOpen(true)}
              className="p-2 hover:bg-slate-800 rounded-lg transition-colors text-slate-400 hover:text-white relative"
            >
              <History size={20} />
              {favorites.length > 0 && (
                <span className="absolute top-1.5 right-1.5 w-2 h-2 bg-pink-500 rounded-full"></span>
              )}
            </button>

            <button 
              onClick={handleStumble}
              disabled={status === 'loading'}
              className="hidden sm:flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white font-bold py-2 px-6 rounded-lg transition-all transform active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed shadow-lg shadow-indigo-500/20"
            >
              {status === 'loading' ? (
                <RefreshCw className="animate-spin" size={20} />
              ) : (
                <Sparkles size={20} />
              )}
              <span>Stumble</span>
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 relative flex flex-col items-center justify-center p-4 overflow-hidden">

        {/* Animated Background Blobs */}
        <div className="absolute top-20 left-10 w-72 h-72 bg-purple-600 rounded-full mix-blend-multiply filter blur-3xl opacity-10 animate-blob"></div>
        <div className="absolute top-20 right-10 w-72 h-72 bg-indigo-600 rounded-full mix-blend-multiply filter blur-3xl opacity-10 animate-blob animation-delay-2000"></div>
        <div className="absolute -bottom-8 left-20 w-72 h-72 bg-pink-600 rounded-full mix-blend-multiply filter blur-3xl opacity-10 animate-blob animation-delay-4000"></div>

        {showWelcome ? (
          <div className="text-center max-w-2xl z-10 animate-fade-in">
            <div className="mb-6 inline-flex items-center justify-center p-3 bg-indigo-500/10 rounded-2xl border border-indigo-500/20">
               <Rabbit size={48} className="text-indigo-400" />
            </div>
            <h1 className="text-5xl md:text-7xl font-display font-bold text-white mb-6 tracking-tighter">
              Dive into the <br/>
              <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-400 to-pink-400">Weird Web</span>
            </h1>
            <p className="text-xl text-slate-400 mb-10 leading-relaxed">
              Break free from the algorithm. Discover curated, obscure, and delightful websites that still feel human.
            </p>

            <div className="flex flex-col sm:flex-row gap-4 justify-center items-center">
              <button 
                onClick={handleStumble}
                className="group relative inline-flex items-center gap-3 bg-white text-slate-900 font-bold py-4 px-8 rounded-xl text-xl hover:bg-indigo-50 transition-all transform hover:-translate-y-1 shadow-2xl shadow-indigo-500/30 w-full sm:w-auto justify-center"
              >
                <Sparkles className="text-indigo-600 group-hover:rotate-12 transition-transform" />
                Start Stumbling
              </button>

              <div className="flex items-center gap-2 text-slate-500 text-sm mt-4 sm:mt-0">
                <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
                AI Curator Ready
              </div>
            </div>
          </div>
        ) : (
          <div className="w-full max-w-4xl z-10 animate-fade-in min-h-[500px] flex items-center justify-center">
            {status === 'loading' ? (
