                 <div className="w-16 h-16 border-4 border-indigo-500/30 border-t-indigo-500 rounded-full animate-spin mx-auto mb-4"></div>
                 <p className="text-slate-400 font-display animate-pulse text-lg">Locating signal...</p>
              </div>
            ) : currentSite ? (
              <SiteCard 
                site={currentSite} 
                isFavorite={favorites.some(f => f.id === currentSite.id)}
                onToggleFavorite={toggleFavorite}
                onVisit={() => window.open(currentSite.url, '_blank')}
              />
            ) : (
               <div className="text-center text-slate-500">
                 <AlertCircle size={48} className="mx-auto mb-2 opacity-50" />
                 <p>Something went wrong. Try stumbling again.</p>
                 <button onClick={handleStumble} className="mt-4 text-indigo-400 hover:underline">Retry</button>
               </div>
            )}
          </div>
        )}

        {/* Mobile Stumble FAB */}
        {!showWelcome && (
          <button 
            onClick={handleStumble}
            className="sm:hidden fixed bottom-6 right-6 z-50 bg-indigo-600 text-white p-4 rounded-full shadow-2xl shadow-indigo-500/40 active:scale-90 transition-transform"
          >
            {status === 'loading' ? <RefreshCw className="animate-spin" /> : <Sparkles />}
          </button>
        )}
      </main>

      {/* Sidebar Drawer */}
      <div className={`fixed inset-y-0 right-0 z-50 w-80 bg-slate-900 border-l border-slate-800 transform transition-transform duration-300 ease-in-out ${isSidebarOpen ? 'translate-x-0' : 'translate-x-full'} shadow-2xl`}>
        <div className="p-4 border-b border-slate-800 flex justify-between items-center bg-slate-900/50 backdrop-blur">
          <h2 className="font-display font-bold text-lg text-white">Your Journey</h2>
          <button onClick={() => setIsSidebarOpen(false)} className="text-slate-400 hover:text-white">
            <X size={24} />
          </button>
        </div>

        <div className="p-4 h-[calc(100%-60px)] overflow-y-auto">
          {favorites.length > 0 && (
             <div className="mb-8">
               <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-3 flex items-center gap-2">
                 <Heart size={12} className="text-pink-500" /> Favorites
               </h3>
               <div className="space-y-3">
                 {favorites.map(site => (
                   <div key={site.id} className="bg-slate-800/50 rounded-lg p-3 border border-slate-700 hover:border-indigo-500/50 transition-colors group cursor-pointer" onClick={() => { setCurrentSite(site); setIsSidebarOpen(false); setShowWelcome(false); }}>
                      <div className="flex justify-between items-start">
                        <h4 className="font-bold text-slate-200 text-sm line-clamp-1">{site.title}</h4>
                        <button onClick={(e) => { e.stopPropagation(); toggleFavorite(site); }} className="text-pink-500 opacity-0 group-hover:opacity-100 transition-opacity">
                          <X size={14} />
                        </button>
                      </div>
                      <p className="text-xs text-slate-400 mt-1 line-clamp-2">{site.description}</p>
                   </div>
                 ))}
               </div>
             </div>
          )}

          <div>
             <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-3 flex items-center gap-2">
               <History size={12} /> Recent Stumbles
             </h3>
             <div className="space-y-3">
               {history.map((site, idx) => (
                 <div key={`${site.id}-${idx}`} className="group bg-slate-800/30 rounded-lg p-3 border border-transparent hover:bg-slate-800 transition-colors cursor-pointer" onClick={() => { setCurrentSite(site); setIsSidebarOpen(false); setShowWelcome(false); }}>
                    <div className="flex justify-between items-center mb-1">
                      <h4 className="font-medium text-slate-300 text-sm line-clamp-1 group-hover:text-indigo-300 transition-colors">{site.title}</h4>
                      <span className={`text-[10px] px-1.5 py-0.5 rounded ${CATEGORY_COLORS[site.category]} text-white/90`}>
                        {site.category.split(' ')[0]}
                      </span>
                    </div>
                    <div className="flex items-center gap-1 text-xs text-slate-500">
                      <ExternalLink size={10} />
                      <span className="truncate">{new URL(site.url).hostname}</span>
                    </div>
                 </div>
               ))}
               {history.length === 0 && (
                 <p className="text-sm text-slate-600 italic text-center py-4">No stumbles yet.</p>
               )}
             </div>
          </div>
        </div>
      </div>

      {/* Overlay for Sidebar */}
      {isSidebarOpen && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-40" onClick={() => setIsSidebarOpen(false)}></div>
      )}

    </div>
  );
};

