             <div className="space-y-3">
               {history.map((site, idx) => (
                 <div key={`${site.id}-${idx}`} className="group bg-slate-800/30 rounded-lg p-3 border border-transparent hover:bg-slate-800 transition-colors cursor-pointer" onClick={() => { setCurrentSite(site); setIsSidebarOpen(false); setShowWelcome(false); }}>
                    <div className="flex justify-between items-center mb-1">
                      <h4 className="font-medium text-slate-300 text-sm line-clamp-1 group-hover:text-indigo-300 transition-colors">{site.title}</h4>
                      <span className={`text-[10px] px-1.5 py-0.5 rounded ${CATEGORY_COLORS[site.category]} text-white/90`}>
                        {site.category.split(' ')[0]}
                      </span>
                    </div>
                    <div className="flex items-center gap-1 text-xs text-slate-500">
                      <ExternalLink size={10} />
                      <span className="truncate">{new URL(site.url).hostname}</span>
                    </div>
                 </div>
               ))}
               {history.length === 0 && (
                 <p className="text-sm text-slate-600 italic text-center py-4">No stumbles yet.</p>
               )}
             </div>
          </div>
        </div>
      </div>

      {/* Overlay for Sidebar */}
      {isSidebarOpen && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-40" onClick={() => setIsSidebarOpen(false)}></div>
      )}

    </div>
  );
};

