import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Rabbit, History, Sparkles, AlertCircle, RefreshCw, Menu, X, ExternalLink, Github, Heart, Tag } from 'lucide-react';
import { Site, Category, FetchStatus } from './types';
import { INITIAL_SITES, CATEGORY_COLORS } from './constants';
import { fetchRecommendations } from './services/geminiService';
import { SiteCard } from './components/SiteCard';

// Hook for local storage
function useLocalStorage<T>(key: string, initialValue: T): [T, React.Dispatch<React.SetStateAction<T>>] {
  const [storedValue, setStoredValue] = useState<T>(() => {
    try {
      const item = window.localStorage.getItem(key);
      return item ? JSON.parse(item) : initialValue;
    } catch (error) {
      console.error(error);
      return initialValue;
    }
  });

  const setValue = (value: React.SetStateAction<T>) => {
    try {
      // Allow value to be a function so we have same API as useState
      const valueToStore =
        value instanceof Function ? (value as (val: T) => T)(storedValue) : value;

      setStoredValue(valueToStore);
      window.localStorage.setItem(key, JSON.stringify(valueToStore));
    } catch (error) {
      console.error(error);
    }
  };

  return [storedValue, setValue];
}

const App: React.FC = () => {
  // State
  const [currentSite, setCurrentSite] = useState<Site | null>(null);
  const [status, setStatus] = useState<FetchStatus>('idle');
  const [selectedCategory, setSelectedCategory] = useState<Category>(Category.ALL);
  const [selectedTag, setSelectedTag] = useState<string | null>(null); // New tag filter state
  const [history, setHistory] = useLocalStorage<Site[]>('rabbithole_history', []);
  const [favorites, setFavorites] = useLocalStorage<Site[]>('rabbithole_favorites', []);
  const [siteQueue, setSiteQueue] = useState<Site[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [showWelcome, setShowWelcome] = useState(true);

  // Use refs to handle strict mode double-invocation prevention if needed, 
  // though basic logic handles it.

  const addToHistory = (site: Site) => {
    setHistory(prev => {
      // Avoid duplicates at the top of the stack
      if (prev.length > 0 && prev[0].id === site.id) return prev;
      return [site, ...prev].slice(0, 50); // Keep last 50
    });
  };

  const toggleFavorite = (site: Site) => {
    setFavorites(prev => {
      const exists = prev.find(s => s.id === site.id);
      if (exists) {
        return prev.filter(s => s.id !== site.id);
      }
      return [site, ...prev];
    });
  };

  const fetchMoreSites = useCallback(async (category: Category) => {
    try {
      // Note: We don't currently support passing the tag to Gemini to keep the prompt simple,
      // but the local fallback handles tags excellently.
      const newSites = await fetchRecommendations(category, 3);
      setSiteQueue(prev => [...prev, ...newSites]);
    } catch (e) {
      console.warn("Background fetch failed", e);
    }
  }, []);

  const fallbackStumble = useCallback(() => {
    // Pick random from INITIAL_SITES that fits criteria
    const available = INITIAL_SITES.filter(s => {
       const categoryMatch = selectedCategory === Category.ALL || s.category === selectedCategory;
       const tagMatch = selectedTag ? s.tags.includes(selectedTag) : true;
       // Try not to show the immediate current one again
       const notCurrent = currentSite ? s.id !== currentSite.id : true;
       return categoryMatch && tagMatch && notCurrent;
    });

    // If strict filtering yields nothing, relax the "notCurrent" constraint
    if (available.length === 0) {
       const relaxed = INITIAL_SITES.filter(s => {
          const categoryMatch = selectedCategory === Category.ALL || s.category === selectedCategory;
          const tagMatch = selectedTag ? s.tags.includes(selectedTag) : true;
          return categoryMatch && tagMatch;
       });

       if (relaxed.length === 0) {
         // If still nothing (e.g. tag doesn't exist in category), clear tag and try again
         if (selectedTag) {
           setSelectedTag(null); // Clear invalid tag
           // We will trigger a re-stumble via effect or just return a random one now
           const random = INITIAL_SITES[Math.floor(Math.random() * INITIAL_SITES.length)];
           setCurrentSite(random);
           addToHistory(random);
           setStatus('success');
         } else {
           // Should not happen given INITIAL_SITES is populated
           console.error("No sites found");
         }
         return;
       }

       const random = relaxed[Math.floor(Math.random() * relaxed.length)];
       setCurrentSite(random);
       addToHistory(random);
       setStatus('success');
       return;
    }

    const random = available[Math.floor(Math.random() * available.length)];
    setCurrentSite(random);
    addToHistory(random);
    setStatus('success');
  }, [selectedCategory, selectedTag, currentSite, addToHistory]);

  // The core stumbling logic
  const handleStumble = useCallback(async () => {
    setStatus('loading');
    setShowWelcome(false);

    // 1. Check Queue first (only if no specific tag filter is active, as queue is category based)
    if (siteQueue.length > 0 && !selectedTag) {
      const nextSite = siteQueue[0];
      setSiteQueue(prev => prev.slice(1));
      setCurrentSite(nextSite);
      addToHistory(nextSite);
      setStatus('success');

      // If queue is getting low, fetch more in background
      if (siteQueue.length < 3) {
        fetchMoreSites(selectedCategory);
      }
      return;
    }

    // 2. If Queue empty or Tag Filter active, use fallback (local db is rich now) or fetch
    // If we have a tag filter, we rely on local DB or we would need to update Gemini prompt.
    // For now, let's rely on the massive local DB for tags, and Gemini for general discovery.
    if (selectedTag) {
        fallbackStumble();
        return;
    }

    try {
      // Try fetching from API
      const newSites = await fetchRecommendations(selectedCategory);

      if (newSites.length > 0) {
        const first = newSites[0];
        const rest = newSites.slice(1);

        setCurrentSite(first);
        addToHistory(first);
        setSiteQueue(rest);
        setStatus('success');
      } else {
        fallbackStumble();
      }
    } catch (e) {
      console.error(e);
      fallbackStumble();
    }
  }, [selectedCategory, selectedTag, siteQueue, fallbackStumble, fetchMoreSites, addToHistory]); 

  // Keyboard Shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Space or ArrowRight to Stumble
      if ((e.code === 'Space' || e.code === 'ArrowRight') && !isSidebarOpen) {
         e.preventDefault(); // Prevent scroll
         if (status !== 'loading') {
            handleStumble();
         }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleStumble, isSidebarOpen, status]);


  // Reset queue when category changes
  useEffect(() => {
    setSiteQueue([]);
  }, [selectedCategory]);

  const handleTagClick = (tag: string) => {
    if (selectedTag === tag) {
      setSelectedTag(null); // Toggle off
    } else {
      setSelectedTag(tag);
      // Optional: immediately stumble when tag selected? 
      // Let's keep current site but next stumble will filter.
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 font-sans selection:bg-indigo-500 selection:text-white flex flex-col">

      {/* Header */}
      <header className="sticky top-0 z-40 w-full border-b border-slate-800 bg-slate-950/80 backdrop-blur-md">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setShowWelcome(true)}>
            <div className="bg-indigo-600 p-2 rounded-lg">
              <Rabbit className="text-white" size={24} />
            </div>
            <span className="font-display font-bold text-xl tracking-tight text-white hidden sm:block">
              Rabbit<span className="text-indigo-400">Hole</span>
            </span>
          </div>

          <div className="flex items-center gap-4">

            {/* Filter Controls */}
            <div className="flex items-center gap-2">
              <div className="hidden md:flex items-center gap-2 bg-slate-900 p-1 rounded-lg border border-slate-800">
                <select 
                    value={selectedCategory}
                    onChange={(e) => {
                      setSelectedCategory(e.target.value as Category);
                      setSelectedTag(null); // Clear tag on category change
                    }}
                    className="bg-transparent text-sm font-medium text-slate-300 px-3 py-1.5 rounded-md focus:outline-none focus:bg-slate-800 cursor-pointer"
                >
                  {Object.values(Category).map(cat => (
                    <option key={cat} value={cat}>{cat}</option>
                  ))}
                </select>
              </div>

              {selectedTag && (
                <button 
                  onClick={() => setSelectedTag(null)}
                  className="flex items-center gap-1 text-xs bg-indigo-600 text-white px-2 py-1 rounded-full hover:bg-indigo-500 transition-colors"
                >
                  <Tag size={12} /> #{selectedTag} <X size={12} />
                </button>
              )}
            </div>

            <button 
              onClick={() => setIsSidebarOpen(true)}
              className="p-2 hover:bg-slate-800 rounded-lg transition-colors text-slate-400 hover:text-white relative"
            >
