// Hook for local storage
function useLocalStorage<T>(key: string, initialValue: T): [T, React.Dispatch<React.SetStateAction<T>>] {
  const [storedValue, setStoredValue] = useState<T>(() => {
    try {
      const item = window.localStorage.getItem(key);
      return item ? JSON.parse(item) : initialValue;
    } catch (error) {
      console.error(error);
      return initialValue;
    }
  });

  const setValue = (value: React.SetStateAction<T>) => {
    try {
      const valueToStore =
        value instanceof Function ? (value as (val: T) => T)(storedValue) : value;

      setStoredValue(valueToStore);
      window.localStorage.setItem(key, JSON.stringify(valueToStore));
    } catch (error) {
      console.error(error);
    }
  };

  return [storedValue, setValue];
}

const App: React.FC = () => {
  // State
  const [currentSite, setCurrentSite] = useState<Site | null>(null);
  const [status, setStatus] = useState<FetchStatus>('idle');
  const [selectedCategory, setSelectedCategory] = useState<Category>(Category.ALL);
  const [selectedTag, setSelectedTag] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [isSearchActive, setIsSearchActive] = useState(false);

  const [history, setHistory] = useLocalStorage<Site[]>('rabbithole_history', []);
  const [favorites, setFavorites] = useLocalStorage<Site[]>('rabbithole_favorites', []);
  const [siteQueue, setSiteQueue] = useState<Site[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [showWelcome, setShowWelcome] = useState(true);
  const searchInputRef = useRef<HTMLInputElement>(null);

  const addToHistory = (site: Site) => {
    setHistory(prev => {
      if (prev.length > 0 && prev[0].id === site.id) return prev;
      return [site, ...prev].slice(0, 50);
    });
  };

  const toggleFavorite = (site: Site) => {
    setFavorites(prev => {
      const exists = prev.find(s => s.id === site.id);
      if (exists) {
        return prev.filter(s => s.id !== site.id);
      }
      return [site, ...prev];
    });
  };

  const fetchMoreSites = useCallback(async (category: Category) => {
    try {
      const newSites = await fetchRecommendations(category, 3);
      setSiteQueue(prev => [...prev, ...newSites]);
    } catch (e) {
      console.warn("Background fetch failed", e);
    }
  }, []);

  const handleSearch = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!searchQuery.trim()) return;

    setStatus('loading');
    setShowWelcome(false);
    setIsSearchActive(true);
    setSiteQueue([]); // Clear normal queue

    try {
      const results = await searchSites(searchQuery);
      if (results.length > 0) {
        const first = results[0];
        const rest = results.slice(1);
        setCurrentSite(first);
        addToHistory(first);
        setSiteQueue(rest);
        setStatus('success');
      } else {
        setStatus('error'); // Or handle empty results gracefully
        // Fallback to random stumble if search fails completely?
        // fallbackStumble();
      }
    } catch (err) {
      console.error(err);
      setStatus('error');
    }
  };

  const fallbackStumble = useCallback(() => {
    const available = INITIAL_SITES.filter(s => {
       const categoryMatch = selectedCategory === Category.ALL || s.category === selectedCategory;
       const tagMatch = selectedTag ? s.tags.includes(selectedTag) : true;
       const notCurrent = currentSite ? s.id !== currentSite.id : true;
       return categoryMatch && tagMatch && notCurrent;
    });

    if (available.length === 0) {
       const relaxed = INITIAL_SITES.filter(s => {
          const categoryMatch = selectedCategory === Category.ALL || s.category === selectedCategory;
          const tagMatch = selectedTag ? s.tags.includes(selectedTag) : true;
          return categoryMatch && tagMatch;
       });

       if (relaxed.length === 0) {
         if (selectedTag) {
           setSelectedTag(null);
           const random = INITIAL_SITES[Math.floor(Math.random() * INITIAL_SITES.length)];
           setCurrentSite(random);
           addToHistory(random);
           setStatus('success');
         }
         return;
       }

       const random = relaxed[Math.floor(Math.random() * relaxed.length)];
       setCurrentSite(random);
       addToHistory(random);
       setStatus('success');
       return;
    }

    const random = available[Math.floor(Math.random() * available.length)];
    setCurrentSite(random);
    addToHistory(random);
    setStatus('success');
  }, [selectedCategory, selectedTag, currentSite, addToHistory]);

  const handleStumble = useCallback(async () => {
    setStatus('loading');
    setShowWelcome(false);

    // If we are in "Search Mode" and have queue, continue search results
    if (isSearchActive && siteQueue.length > 0) {
        const nextSite = siteQueue[0];
        setSiteQueue(prev => prev.slice(1));
        setCurrentSite(nextSite);
        addToHistory(nextSite);
        setStatus('success');
        return;
    } else if (isSearchActive && siteQueue.length === 0) {
        // If search queue empty, maybe search again? or fallback?
        // Let's search again to give "infinite" results for the query
        await handleSearch(); 
        return;
    }

    // Normal Stumble Logic
    if (siteQueue.length > 0 && !selectedTag) {
      const nextSite = siteQueue[0];
      setSiteQueue(prev => prev.slice(1));
      setCurrentSite(nextSite);
      addToHistory(nextSite);
      setStatus('success');

      if (siteQueue.length < 3) {
        fetchMoreSites(selectedCategory);
      }
      return;
    }

    if (selectedTag) {
        fallbackStumble();
        return;
    }

    try {
      const newSites = await fetchRecommendations(selectedCategory);
      if (newSites.length > 0) {
        const first = newSites[0];
        const rest = newSites.slice(1);
        setCurrentSite(first);
        addToHistory(first);
        setSiteQueue(rest);
        setStatus('success');
      } else {
        fallbackStumble();
      }
    } catch (e) {
      console.error(e);
      fallbackStumble();
    }
  }, [selectedCategory, selectedTag, siteQueue, fallbackStumble, fetchMoreSites, addToHistory, isSearchActive, searchQuery]); 

  // Keyboard Shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Focus search with '/'
      if (e.key === '/' && !isSidebarOpen && document.activeElement !== searchInputRef.current) {
        e.preventDefault();
        searchInputRef.current?.focus();
        return;
      }

      // Space or ArrowRight to Stumble
      if ((e.code === 'Space' || e.code === 'ArrowRight') && !isSidebarOpen && document.activeElement !== searchInputRef.current) {
         e.preventDefault();
         if (status !== 'loading') {
            handleStumble();
         }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleStumble, isSidebarOpen, status]);

  useEffect(() => {
    setSiteQueue([]);
    // Only turn off search mode if we explicitly changed categories, 
    // not just on mount or tag change (tags work within search technically, but complex to implement)
    if (isSearchActive) {
      // We keep search active unless user selects a new category manually
      // But here we can't detect "user action". 
      // Simple logic: Category change resets search.
      setIsSearchActive(false);
      setSearchQuery('');
    }
  }, [selectedCategory]);

  const handleTagClick = (tag: string) => {
    if (selectedTag === tag) {
      setSelectedTag(null);
    } else {
      setSelectedTag(tag);
      setIsSearchActive(false); // Reset search if we click a tag
      setSearchQuery('');
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 font-sans selection:bg-indigo-500 selection:text-white flex flex-col">

      {/* Header */}
      <header className="sticky top-0 z-40 w-full border-b border-slate-800 bg-slate-950/80 backdrop-blur-md">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between gap-4">
          <div className="flex items-center gap-2 cursor-pointer flex-shrink-0" onClick={() => setShowWelcome(true)}>
            <div className="bg-indigo-600 p-2 rounded-lg">
              <Rabbit className="text-white" size={24} />
            </div>
            <span className="font-display font-bold text-xl tracking-tight text-white hidden md:block">
              Rabbit<span className="text-indigo-400">Hole</span>
            </span>
          </div>

          <div className="flex-1 max-w-md hidden sm:block relative group">
             <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
               <Search size={16} className="text-slate-500 group-focus-within:text-indigo-400 transition-colors" />
             </div>
             <form onSubmit={handleSearch}>
               <input 
                 ref={searchInputRef}
                 type="text" 
                 placeholder="Search for weird sites... (e.g. 'scary', 'cats', 'math')" 
                 className="w-full bg-slate-900 border border-slate-700 text-slate-200 text-sm rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent block pl-10 p-2.5 transition-all outline-none"
                 value={searchQuery}
                 onChange={(e) => setSearchQuery(e.target.value)}
               />
             </form>
             <div className="absolute inset-y-0 right-0 pr-3 flex items-center pointer-events-none">
                <span className="text-xs text-slate-600 border border-slate-700 rounded px-1.5 py-0.5 hidden group-focus-within:block">Enter</span>
                <span className="text-xs text-slate-600 border border-slate-700 rounded px-1.5 py-0.5 group-focus-within:hidden">/</span>
             </div>
          </div>

          <div className="flex items-center gap-3 flex-shrink-0">
            {/* Category Select - Hide on very small screens if needed, or compact it */}
            <div className="hidden lg:flex items-center gap-2 bg-slate-900 p-1 rounded-lg border border-slate-800">
                <select 
                    value={selectedCategory}
                    onChange={(e) => setSelectedCategory(e.target.value as Category)}
                    className="bg-transparent text-sm font-medium text-slate-300 px-3 py-1.5 rounded-md focus:outline-none focus:bg-slate-800 cursor-pointer"
                >
                  {Object.values(Category).map(cat => (
                    <option key={cat} value={cat}>{cat}</option>
                  ))}
                </select>
            </div>

            {selectedTag && (
                <button 
                  onClick={() => setSelectedTag(null)}
                  className="hidden md:flex items-center gap-1 text-xs bg-indigo-600 text-white px-2 py-1 rounded-full hover:bg-indigo-500 transition-colors"
                >
                  <Tag size={12} /> #{selectedTag} <X size={12} />
                </button>
            )}

            <button 
              onClick={() => setIsSidebarOpen(true)}
              className="p-2 hover:bg-slate-800 rounded-lg transition-colors text-slate-400 hover:text-white relative"
            >
              <History size={20} />
              {favorites.length > 0 && (
                <span className="absolute top-1.5 right-1.5 w-2 h-2 bg-pink-500 rounded-full"></span>
              )}
            </button>

            <button 
              onClick={handleStumble}
              disabled={status === 'loading'}
              className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white font-bold py-2 px-4 sm:px-6 rounded-lg transition-all transform active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed shadow-lg shadow-indigo-500/20"
            >
              {status === 'loading' ? (
                <RefreshCw className="animate-spin" size={20} />
              ) : (
                <Sparkles size={20} />
              )}
              <span className="hidden sm:inline">Stumble</span>
            </button>
          </div>
        </div>

        {/* Mobile Search Bar (visible only on small screens) */}
        <div className="sm:hidden px-4 pb-3">
             <form onSubmit={handleSearch} className="relative">
