import { GoogleGenAI, Type } from "@google/genai";
import { Site, Category } from '../types';
import { v4 as uuidv4 } from 'uuid';

const apiKey = process.env.API_KEY || '';

// Initialize client ONLY if key exists.
const ai = apiKey ? new GoogleGenAI({ apiKey }) : null;

// Helper to parse Gemini response
const parseResponse = (text: string | undefined): Site[] => {
  if (!text) return [];
  try {
    // Sanitize the text in case it includes markdown code blocks
    const cleanText = text.replace(/```json/g, '').replace(/```/g, '').trim();
    const parsedData = JSON.parse(cleanText);
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    return parsedData.map((item: any) => ({
      ...item,
      id: uuidv4(),
      category: Object.values(Category).includes(item.category) ? item.category : Category.MYSTERY
    }));
  } catch (error) {
    console.error("Failed to parse Gemini response:", error);
    return [];
  }
};

export const fetchRecommendations = async (category: Category, count: number = 3): Promise<Site[]> => {
  if (!ai) {
    console.warn("No API Key found. Returning empty list.");
    return [];
  }

  const categoryPrompt = category === Category.ALL 
    ? "any category, but focus on the weird, obscure, wonderful, and useless web." 
    : `the category '${category}'.`;

  const prompt = `
    I need a list of ${count} REAL, EXISTING, and OBSCURE websites. 
    Focus on ${categoryPrompt}

    CRITICAL RULES:
    1. The websites MUST be real and currently online.
    2. Do NOT invent fake URLs.
    3. Focus on "The Useless Web", "Neocities" gems, "Net Art", niche museums, interactive experiments, or unique single-serving sites.
    4. Avoid mainstream social media or standard corporate sites.
    5. Avoid AI-generated content farms.

    Return a valid JSON array of objects.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              url: { type: Type.STRING },
              description: { type: Type.STRING },
              category: { type: Type.STRING, description: "Match one of: Interactive Art, The Useless Web, Educational, Retro/Nostalgia, Niche Tools, Mystery, Music/Audio" },
              tags: { type: Type.ARRAY, items: { type: Type.STRING } },
              yearEstablished: { type: Type.STRING, description: "Approximate year or 'Unknown'" },
              curatorNote: { type: Type.STRING, description: "A witty or intriguing reason to visit this site." }
            },
            required: ['title', 'url', 'description', 'category', 'tags']
          }
        }
      }
    });

    return parseResponse(response.text);

  } catch (error) {
    console.error("Gemini discovery failed:", error);
    return [];
  }
};

export const searchSites = async (query: string, count: number = 3): Promise<Site[]> => {
  if (!ai) return [];

  const prompt = `
    Use Google Search to find ${count} REAL, UNIQUE, and INTERESTING websites that match this user request: "${query}".

    CRITICAL INSTRUCTIONS:
    1. Use the googleSearch tool to find actual, live URLs.
    2. Prefer independent, non-commercial, or "weird" web results over generic articles.
    3. If the user asks for "scary", "funny", or "useless", find specific sites that do that.
    4. Return the results as a JSON array.

    Schema:
    [
      {
        "title": "Site Title",
        "url": "https://...",
        "description": "Short description...",
        "category": "Category",
        "tags": ["tag1", "tag2"],
        "curatorNote": "Why this matches the search"
      }
    ]
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview', 
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }], // ENABLED SEARCH API
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              url: { type: Type.STRING },
              description: { type: Type.STRING },
              category: { type: Type.STRING },
              tags: { type: Type.ARRAY, items: { type: Type.STRING } },
              yearEstablished: { type: Type.STRING },
              curatorNote: { type: Type.STRING, description: `Explain why this matches "${query}"` }
            },
            required: ['title', 'url', 'description', 'category', 'tags']
          }
        }
      }
    });

    // When using tools, sometimes the text is empty if the model decides to only call the tool,
    // but with responseSchema it usually forces the output.
    // If we used Google Search, we might want to log grounding metadata for debugging.
    // console.log(response.candidates?.[0]?.groundingMetadata?.groundingChunks);

    return parseResponse(response.text);
  } catch (error) {
    console.error("Gemini search failed:", error);
    return [];
  }
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Rabbit, History, Sparkles, AlertCircle, RefreshCw, X, ExternalLink, Heart, Tag, Search, Ghost, Music, Gamepad2, Palette, Tv } from 'lucide-react';
import { Site, Category, FetchStatus } from './types';
