         e.preventDefault();
         if (status !== 'loading') {
            handleStumble();
         }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleStumble, isSidebarOpen, status]);

  useEffect(() => {
    setSiteQueue([]);
    if (isSearchActive) {
      setIsSearchActive(false);
      setSearchQuery('');
    }
  }, [selectedCategory]);

