    }));

    return parseResponse(response.text);
  } catch (error) {
    console.error("Gemini similarity search failed:", error);
    return [];
  }
};

export const getSiteAnalysis = async (site: Site, persona: CuratorPersona): Promise<string> => {
    if (!ai) return "AI connection unavailable.";

    const prompt = `
        ${persona.promptModifier}

        TASK: Perform a "Deep Analysis" of this website: ${site.title} (${site.url}).

        Provide a 100-150 word breakdown covering:
        1. What makes it unique?
        2. The "vibe" or aesthetic.
        3. Why it matters (or why it doesn't).

        Keep the tone consistent with your Persona.
    `;

    try {
        const response = await withRetry(() => ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                tools: [{ googleSearch: {} }],
            }
        }));

        return response.text || "Analysis failed.";
    } catch (e) {
        console.error(e);
        return "Neural link severed. Analysis data unavailable due to network interference.";
    }
}

