  const handleStumble = useCallback(async () => {
    playSound('static');
    setStatus('loading');
    setShowWelcome(false);
    setCurrentAnalysis(null);

    if (isSearchActive && siteQueue.length > 0) {
        const nextSite = siteQueue[0];
        setSiteQueue(prev => prev.slice(1));
        setCurrentSite(nextSite);
        addToHistory(nextSite);
        playSound('success');
        setStatus('success');
        return;
    } else if (isSearchActive && siteQueue.length === 0) {
        // If searching "similar", maybe just use search API again with title
        if (searchQuery.startsWith('Similar to:')) {
             await handleSearch(undefined, searchQuery.replace('Similar to:', 'websites like'));
        } else {
             await handleSearch(undefined, searchQuery); 
        }
        return;
    }

    if (siteQueue.length > 0 && !selectedTag) {
      const nextSite = siteQueue[0];
      setSiteQueue(prev => prev.slice(1));
      setCurrentSite(nextSite);
      addToHistory(nextSite);
      playSound('success');
      setStatus('success');

      if (siteQueue.length < 3) {
        fetchMoreSites(selectedCategory);
      }
      return;
    }

    if (selectedTag) {
        fallbackStumble();
        return;
    }

    try {
      const newSites = await fetchRecommendations(selectedCategory, activePersona);
      if (newSites.length > 0) {
        const first = newSites[0];
        const rest = newSites.slice(1);
        setCurrentSite(first);
        addToHistory(first);
        setSiteQueue(rest);
        playSound('success');
        setStatus('success');
      } else {
        fallbackStumble();
      }
    } catch (e) {
      console.error(e);
      fallbackStumble();
    }
  }, [selectedCategory, selectedTag, siteQueue, fallbackStumble, fetchMoreSites, addToHistory, isSearchActive, searchQuery, activePersona]); 

  // Reset queue when persona changes to ensure new recommendations match the vibe
  useEffect(() => {
    setSiteQueue([]);
  }, [activePersona]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === '/' && !isSidebarOpen && document.activeElement !== searchInputRef.current) {
        e.preventDefault();
        searchInputRef.current?.focus();
        return;
      }
      if ((e.code === 'Space' || e.code === 'ArrowRight') && !isSidebarOpen && document.activeElement !== searchInputRef.current) {
         e.preventDefault();
         if (status !== 'loading') {
            handleStumble();
         }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleStumble, isSidebarOpen, status]);

  useEffect(() => {
    setSiteQueue([]);
    if (isSearchActive) {
      setIsSearchActive(false);
      setSearchQuery('');
    }
  }, [selectedCategory]);

  const handleTagClick = (tag: string) => {
    playSound('blip');
    if (selectedTag === tag) {
      setSelectedTag(null);
    } else {
      setSelectedTag(tag);
      setIsSearchActive(false); 
      setSearchQuery('');
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 font-sans selection:bg-indigo-500 selection:text-white flex flex-col relative overflow-hidden">

      {/* CRT Scanline Effect */}
      {retroMode && (
