// --- Config Helper ---
const getConfig = (model: AIModel, thinkingBudget: number) => {
    const baseConfig: any = {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
    };

    // Apply thinking config if model supports it AND budget > 0
    if (model.supportsThinking && thinkingBudget > 0) {
        // Ensure budget doesn't exceed model max
        const budget = Math.min(thinkingBudget, model.maxThinkingBudget || 8192);

        // When using thinking, we usually want to set maxOutputTokens to something reasonable 
        // to allow room for the thinking process + response.
        // Rule: maxOutputTokens >= thinkingBudget + responseLength. 
        // We'll give it plenty of room.
        baseConfig.maxOutputTokens = budget + 2048; 
        baseConfig.thinkingConfig = { thinkingBudget: budget };
    }

    return baseConfig;
};


