// --- Sound Engine ---
const playSound = (type: 'static' | 'blip' | 'success') => {
  try {
    const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
    if (!AudioContext) return;
    const ctx = new AudioContext();
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.connect(gain);
    gain.connect(ctx.destination);

    const now = ctx.currentTime;

    if (type === 'static') {
      osc.type = 'sawtooth';
      osc.frequency.setValueAtTime(100, now);
      osc.frequency.linearRampToValueAtTime(800, now + 0.1);
      gain.gain.setValueAtTime(0.05, now);
      gain.gain.exponentialRampToValueAtTime(0.001, now + 0.15);
      osc.start(now);
      osc.stop(now + 0.15);
    } else if (type === 'blip') {
      osc.type = 'sine';
      osc.frequency.setValueAtTime(800, now);
      osc.frequency.exponentialRampToValueAtTime(400, now + 0.1);
      gain.gain.setValueAtTime(0.1, now);
      gain.gain.linearRampToValueAtTime(0, now + 0.1);
      osc.start(now);
      osc.stop(now + 0.1);
    } else if (type === 'success') {
      osc.type = 'triangle';
      osc.frequency.setValueAtTime(300, now);
      osc.frequency.linearRampToValueAtTime(600, now + 0.2);
      gain.gain.setValueAtTime(0.1, now);
      gain.gain.linearRampToValueAtTime(0, now + 0.4);
      osc.start(now);
      osc.stop(now + 0.4);
    }
  } catch (e) {
    // Ignore audio errors
  }
};

// --- Hook for local storage ---
function useLocalStorage<T>(key: string, initialValue: T): [T, React.Dispatch<React.SetStateAction<T>>] {
  const [storedValue, setStoredValue] = useState<T>(() => {
    try {
      const item = window.localStorage.getItem(key);
      return item ? JSON.parse(item) : initialValue;
    } catch (error) {
      console.error(error);
      return initialValue;
    }
  });

  const setValue = (value: React.SetStateAction<T>) => {
    try {
      const valueToStore = value instanceof Function ? (value as (val: T) => T)(storedValue) : value;
      setStoredValue(valueToStore);
      window.localStorage.setItem(key, JSON.stringify(valueToStore));
    } catch (error) {
      console.error(error);
    }
  };

  return [storedValue, setValue];
}

const COLLECTIONS = [
  { id: 'spooky', label: 'Spooky', icon: Ghost, query: 'scary creepy unsettling websites' },
  { id: 'zen', label: 'Zen Mode', icon: Music, query: 'relaxing ambient peaceful interactive websites' },
  { id: 'retro', label: '90s Web', icon: Gamepad2, query: '90s geocities nostalgia web design' },
  { id: 'art', label: 'Net Art', icon: Palette, query: 'weird internet art experiments' },
];

const App: React.FC = () => {
  // State
  const [currentSite, setCurrentSite] = useState<Site | null>(null);
  const [status, setStatus] = useState<FetchStatus>('idle');
  const [selectedCategory, setSelectedCategory] = useState<Category>(Category.ALL);
  const [selectedTag, setSelectedTag] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [isSearchActive, setIsSearchActive] = useState(false);
  const [retroMode, setRetroMode] = useLocalStorage('retro_mode', true);

  // AI Model & Config State
  const [activePersona, setActivePersona] = useState<CuratorPersona>(CURATOR_PERSONAS[0]);
  const [activeModel, setActiveModel] = useState<AIModel>(AI_MODELS[0]);
  const [thinkingBudget, setThinkingBudget] = useState<number>(0);

  const [showConfig, setShowConfig] = useState(false);
  const [currentAnalysis, setCurrentAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const [history, setHistory] = useLocalStorage<Site[]>('rabbithole_history', []);
  const [favorites, setFavorites] = useLocalStorage<Site[]>('rabbithole_favorites', []);
  const [siteQueue, setSiteQueue] = useState<Site[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [showWelcome, setShowWelcome] = useState(true);
  const searchInputRef = useRef<HTMLInputElement>(null);

  const addToHistory = (site: Site) => {
    setHistory(prev => {
      if (prev.length > 0 && prev[0].id === site.id) return prev;
      return [site, ...prev].slice(0, 50);
    });
  };

  const toggleFavorite = (site: Site) => {
    setFavorites(prev => {
      const exists = prev.find(s => s.id === site.id);
      if (exists) {
        return prev.filter(s => s.id !== site.id);
      }
      return [site, ...prev];
    });
  };

  const fetchMoreSites = useCallback(async (category: Category) => {
    try {
      const newSites = await fetchRecommendations(category, activePersona, activeModel, thinkingBudget, 3);
      setSiteQueue(prev => [...prev, ...newSites]);
    } catch (e) {
      console.warn("Background fetch failed", e);
    }
  }, [activePersona, activeModel, thinkingBudget]); 

  const handleSearch = async (e?: React.FormEvent, overrideQuery?: string) => {
    if (e) e.preventDefault();
    const q = overrideQuery || searchQuery;
    if (!q.trim()) return;

    if (overrideQuery) setSearchQuery(overrideQuery);

    playSound('static');
    setStatus('loading');
    setShowWelcome(false);
    setIsSearchActive(true);
    setCurrentAnalysis(null);
    setSiteQueue([]); 

    try {
      let results = await searchSites(q, activePersona, activeModel, thinkingBudget);

      // FALLBACK
      if (results.length === 0) {
          console.warn("API unavailable, falling back to local search.");
          const lowerQ = q.toLowerCase();
          const localResults = INITIAL_SITES.filter(s => 
             s.title.toLowerCase().includes(lowerQ) || 
             s.description.toLowerCase().includes(lowerQ) ||
             s.tags.some(t => t.toLowerCase().includes(lowerQ)) ||
             s.category.toLowerCase().includes(lowerQ)
          );
          results = localResults.sort(() => 0.5 - Math.random()).slice(0, 3);
      }

      if (results.length > 0) {
        playSound('success');
        const first = results[0];
        const rest = results.slice(1);
        setCurrentSite(first);
        addToHistory(first);
        setSiteQueue(rest);
        setStatus('success');
      } else {
        setStatus('error');
      }
    } catch (err) {
      console.error(err);
      setStatus('error');
    }
  };

  const handleFindSimilar = async (site: Site) => {
    playSound('static');
    setStatus('loading');
    setSiteQueue([]);
    setCurrentAnalysis(null);
    setIsSearchActive(true);
    setSearchQuery(`Similar to: ${site.title}`);

    try {
      let results = await findSimilarSites(site.url, site.title, activeModel, thinkingBudget);

      // FALLBACK
      if (results.length === 0) {
          console.warn("API unavailable, falling back to local similar check.");
          const localResults = INITIAL_SITES.filter(s => 
              s.id !== site.id && 
              (s.category === site.category || s.tags.some(t => site.tags.includes(t)))
          );
          results = localResults.sort(() => 0.5 - Math.random()).slice(0, 3);
      }

      if (results.length > 0) {
        playSound('success');
        const first = results[0];
        const rest = results.slice(1);
        setCurrentSite(first);
        addToHistory(first);
        setSiteQueue(rest);
        setStatus('success');
      } else {
        setStatus('error');
      }
    } catch (err) {
        console.error(err);
        setStatus('error');
    }
  };

  const handleAnalyzeSite = async (site: Site) => {
      setIsAnalyzing(true);
      setCurrentAnalysis(null);
      try {
          const analysis = await getSiteAnalysis(site, activePersona, activeModel, thinkingBudget);
          setCurrentAnalysis(analysis);
      } catch (e) {
          setCurrentAnalysis("Neural link severed. Local analysis unavailable.");
      } finally {
          setIsAnalyzing(false);
      }
  }

  const fallbackStumble = useCallback(() => {
    const available = INITIAL_SITES.filter(s => {
       const categoryMatch = selectedCategory === Category.ALL || s.category === selectedCategory;
       const tagMatch = selectedTag ? s.tags.includes(selectedTag) : true;
       const notCurrent = currentSite ? s.id !== currentSite.id : true;
       return categoryMatch && tagMatch && notCurrent;
    });

    if (available.length === 0) {
       // Relax "notCurrent"
       const relaxed = INITIAL_SITES.filter(s => {
          const categoryMatch = selectedCategory === Category.ALL || s.category === selectedCategory;
          const tagMatch = selectedTag ? s.tags.includes(selectedTag) : true;
          return categoryMatch && tagMatch;
       });

       if (relaxed.length === 0) {
         if (selectedTag) {
           setSelectedTag(null); 
           const random = INITIAL_SITES[Math.floor(Math.random() * INITIAL_SITES.length)];
           setCurrentSite(random);
           addToHistory(random);
           playSound('success');
           setStatus('success');
         }
         return;
       }

       const random = relaxed[Math.floor(Math.random() * relaxed.length)];
       setCurrentSite(random);
       addToHistory(random);
       playSound('success');
       setStatus('success');
       return;
    }

    const random = available[Math.floor(Math.random() * available.length)];
    setCurrentSite(random);
    addToHistory(random);
    playSound('success');
    setStatus('success');
  }, [selectedCategory, selectedTag, currentSite, addToHistory]);

  const handleStumble = useCallback(async () => {
    playSound('static');
    setStatus('loading');
    setShowWelcome(false);
    setCurrentAnalysis(null);

    if (isSearchActive && siteQueue.length > 0) {
        const nextSite = siteQueue[0];
        setSiteQueue(prev => prev.slice(1));
        setCurrentSite(nextSite);
        addToHistory(nextSite);
        playSound('success');
        setStatus('success');
        return;
    } else if (isSearchActive && siteQueue.length === 0) {
        // If searching "similar", maybe just use search API again with title
        if (searchQuery.startsWith('Similar to:')) {
             await handleSearch(undefined, searchQuery.replace('Similar to:', 'websites like'));
        } else {
             await handleSearch(undefined, searchQuery); 
        }
        return;
    }

    if (siteQueue.length > 0 && !selectedTag) {
      const nextSite = siteQueue[0];
      setSiteQueue(prev => prev.slice(1));
      setCurrentSite(nextSite);
      addToHistory(nextSite);
      playSound('success');
      setStatus('success');

      if (siteQueue.length < 3) {
        fetchMoreSites(selectedCategory);
      }
      return;
    }

    if (selectedTag) {
        fallbackStumble();
        return;
    }

    try {
      const newSites = await fetchRecommendations(selectedCategory, activePersona, activeModel, thinkingBudget);
      if (newSites.length > 0) {
        const first = newSites[0];
        const rest = newSites.slice(1);
        setCurrentSite(first);
        addToHistory(first);
        setSiteQueue(rest);
        playSound('success');
        setStatus('success');
      } else {
        fallbackStumble();
      }
    } catch (e) {
      console.error(e);
      fallbackStumble();
    }
  }, [selectedCategory, selectedTag, siteQueue, fallbackStumble, fetchMoreSites, addToHistory, isSearchActive, searchQuery, activePersona, activeModel, thinkingBudget]); 

  // Reset queue when config changes
  useEffect(() => {
    setSiteQueue([]);
  }, [activePersona, activeModel]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === '/' && !isSidebarOpen && document.activeElement !== searchInputRef.current) {
        e.preventDefault();
        searchInputRef.current?.focus();
        return;
      }
      if ((e.code === 'Space' || e.code === 'ArrowRight') && !isSidebarOpen && document.activeElement !== searchInputRef.current) {
         e.preventDefault();
         if (status !== 'loading') {
            handleStumble();
         }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleStumble, isSidebarOpen, status]);

  useEffect(() => {
    setSiteQueue([]);
    if (isSearchActive) {
      setIsSearchActive(false);
      setSearchQuery('');
    }
  }, [selectedCategory]);

  const handleTagClick = (tag: string) => {
    playSound('blip');
    if (selectedTag === tag) {
      setSelectedTag(null);
    } else {
      setSelectedTag(tag);
      setIsSearchActive(false); 
      setSearchQuery('');
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 font-sans selection:bg-indigo-500 selection:text-white flex flex-col relative overflow-hidden">

      {/* CRT Scanline Effect */}
      {retroMode && (
        <div className="fixed inset-0 pointer-events-none z-50 opacity-[0.05] bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.25)_50%),linear-gradient(90deg,rgba(255,0,0,0.06),rgba(0,255,0,0.02),rgba(0,0,255,0.06))] bg-[length:100%_2px,3px_100%]"></div>
      )}

      {/* Loading Static Overlay */}
      {status === 'loading' && (
        <div className="fixed inset-0 pointer-events-none z-40 opacity-10 animate-pulse bg-white mix-blend-overlay"></div>
      )}

      {/* Header */}
      <header className="sticky top-0 z-40 w-full border-b border-slate-800 bg-slate-950/80 backdrop-blur-md">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between gap-4">
          <div className="flex items-center gap-2 cursor-pointer flex-shrink-0" onClick={() => { setShowWelcome(true); playSound('blip'); }}>
            <div className="bg-indigo-600 p-2 rounded-lg">
              <Rabbit className="text-white" size={24} />
            </div>
            <span className="font-display font-bold text-xl tracking-tight text-white hidden md:block">
              Rabbit<span className="text-indigo-400">Hole</span>
            </span>
          </div>

          <div className="flex-1 max-w-md hidden sm:block relative group">
             <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
               <Search size={16} className="text-slate-500 group-focus-within:text-indigo-400 transition-colors" />
             </div>
             <form onSubmit={(e) => handleSearch(e)}>
               <input 
                 ref={searchInputRef}
                 type="text" 
                 placeholder={`Ask ${activePersona.name}...`} 
                 className="w-full bg-slate-900 border border-slate-700 text-slate-200 text-sm rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent block pl-10 p-2.5 transition-all outline-none"
                 value={searchQuery}
                 onChange={(e) => setSearchQuery(e.target.value)}
               />
             </form>
          </div>

          <div className="flex items-center gap-3 flex-shrink-0">

             {/* Config Toggle */}
             <div className="relative">
                 <button 
                    onClick={() => setShowConfig(!showConfig)}
                    className="flex items-center gap-2 bg-slate-900 border border-slate-800 text-slate-300 px-3 py-2 rounded-lg text-sm hover:bg-slate-800 transition-colors"
                 >
                    <Cpu size={16} className="text-indigo-400"/>
                    <span className="hidden lg:inline">Config</span>
                    <ChevronDown size={14} className={`transition-transform ${showConfig ? 'rotate-180' : ''}`} />
                 </button>

                 {showConfig && (
                     <div className="absolute top-full right-0 mt-2 w-80 bg-slate-900 border border-slate-700 rounded-xl shadow-2xl p-4 z-50 animate-fade-in max-h-[80vh] overflow-y-auto">

                         {/* Persona Selector */}
                         <div className="mb-4">
                             <div className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Curator Persona</div>
                             <div className="space-y-1">
                                {CURATOR_PERSONAS.map(persona => (
                                    <button
                                        key={persona.id}
                                        onClick={() => { setActivePersona(persona); playSound('blip'); }}
                                        className={`w-full text-left p-2 rounded-lg text-sm transition-colors flex items-center gap-3 ${activePersona.id === persona.id ? 'bg-slate-800 text-white border border-slate-700' : 'text-slate-400 hover:bg-slate-800/50 hover:text-slate-200'}`}
                                    >
                                        <div className={`w-2 h-2 rounded-full ${persona.color}`}></div>
                                        <div>
                                            <div className="font-bold">{persona.name}</div>
                                            <div className="text-[10px] opacity-70 line-clamp-1">{persona.description}</div>
                                        </div>
                                    </button>
                                ))}
                             </div>
                         </div>

                         {/* Model Selector */}
                         <div className="mb-4 pt-4 border-t border-slate-800">
                             <div className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Neural Engine</div>
                             <div className="space-y-1">
                                {AI_MODELS.map(model => (
                                    <button
                                        key={model.id}
                                        onClick={() => { setActiveModel(model); playSound('blip'); }}
                                        className={`w-full text-left p-2 rounded-lg text-sm transition-colors ${activeModel.id === model.id ? 'bg-indigo-900/30 text-indigo-300 border border-indigo-500/30' : 'text-slate-400 hover:bg-slate-800/50 hover:text-slate-200'}`}
                                    >
                                        <div className="flex justify-between items-center mb-1">
                                            <span className="font-bold flex items-center gap-2">
                                                {model.name}
                                                {model.isExperimental && <span className="text-[9px] bg-purple-900 text-purple-200 px-1 rounded">EXP</span>}
                                            </span>
                                            <span className="text-[10px] bg-slate-800 px-1.5 rounded">{model.speedLabel}</span>
                                        </div>
                                        <div className="text-[10px] opacity-70 line-clamp-1">{model.description}</div>
                                    </button>
                                ))}
                             </div>
                         </div>

                         {/* Thinking Config */}
                         {activeModel.supportsThinking && (
                             <div className="mb-4 pt-4 border-t border-slate-800">
                                 <div className="flex justify-between items-center mb-2">
                                     <div className="text-xs font-bold text-slate-500 uppercase tracking-wider">Thinking Budget</div>
                                     <div className="text-xs font-mono text-indigo-400">{thinkingBudget} tokens</div>
                                 </div>
                                 <input 
                                    type="range" 
                                    min="0" 
                                    max={activeModel.maxThinkingBudget} 
                                    step="1024"
                                    value={thinkingBudget}
                                    onChange={(e) => setThinkingBudget(Number(e.target.value))}
                                    className="w-full h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500"
                                 />
                                 <div className="flex justify-between text-[9px] text-slate-600 mt-1">
                                     <span>Off</span>
                                     <span>Max ({activeModel.maxThinkingBudget})</span>
                                 </div>
                             </div>
                         )}

                         {/* Stats */}
                         <div className="pt-2 border-t border-slate-800 flex justify-between text-[10px] text-slate-500">
                             <div className="flex items-center gap-1">
                                 <Gauge size={12} />
                                 Quota: {activeModel.rateLimitLabel}
                             </div>
                             <div className="flex items-center gap-1">
                                 <Zap size={12} />
                                 Speed: {activeModel.speedLabel}
                             </div>
                         </div>

                     </div>
                 )}
                 {showConfig && <div className="fixed inset-0 z-40" onClick={() => setShowConfig(false)}></div>}
             </div>

            <button 
                onClick={() => setRetroMode(!retroMode)}
                className={`p-2 rounded-lg transition-colors hidden sm:block ${retroMode ? 'text-indigo-400 bg-indigo-500/10' : 'text-slate-500 hover:text-white'}`}
                title="Toggle CRT Mode"
            >
                <Monitor size={20} />
            </button>

            <button 
              onClick={() => setIsSidebarOpen(true)}
              className="p-2 hover:bg-slate-800 rounded-lg transition-colors text-slate-400 hover:text-white relative"
            >
              <History size={20} />
              {favorites.length > 0 && (
                <span className="absolute top-1.5 right-1.5 w-2 h-2 bg-pink-500 rounded-full"></span>
              )}
            </button>

            <button 
              onClick={handleStumble}
              disabled={status === 'loading'}
              className={`flex items-center gap-2 ${activePersona.color} hover:opacity-90 text-white font-bold py-2 px-4 sm:px-6 rounded-lg transition-all transform active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed shadow-lg`}
            >
              {status === 'loading' ? (
                <RefreshCw className="animate-spin" size={20} />
              ) : (
                <Sparkles size={20} />
              )}
              <span className="hidden sm:inline">Stumble</span>
            </button>
          </div>
        </div>

        {/* Mobile Search Bar */}
        <div className="sm:hidden px-4 pb-3">
             <form onSubmit={(e) => handleSearch(e)} className="relative">
                <input 
                  type="text" 
                  placeholder={`Ask ${activePersona.name}...`} 
                  className="w-full bg-slate-900 border border-slate-700 text-slate-200 text-sm rounded-lg focus:ring-2 focus:ring-indigo-500 p-2 pl-9"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                />
                <Search size={14} className="absolute left-3 top-3 text-slate-500" />
             </form>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 relative flex flex-col items-center justify-center p-4 overflow-hidden">

        <div className="absolute top-20 left-10 w-72 h-72 bg-purple-600 rounded-full mix-blend-multiply filter blur-3xl opacity-10 animate-blob"></div>
        <div className="absolute top-20 right-10 w-72 h-72 bg-indigo-600 rounded-full mix-blend-multiply filter blur-3xl opacity-10 animate-blob animation-delay-2000"></div>
        <div className="absolute -bottom-8 left-20 w-72 h-72 bg-pink-600 rounded-full mix-blend-multiply filter blur-3xl opacity-10 animate-blob animation-delay-4000"></div>

        {showWelcome ? (
          <div className="text-center max-w-3xl z-10 animate-fade-in relative">
            <div className="mb-6 inline-flex items-center justify-center p-4 bg-slate-900/50 rounded-2xl border border-slate-700 backdrop-blur shadow-2xl">
               <Rabbit size={48} className="text-indigo-400" />
            </div>
            <h1 className="text-5xl md:text-7xl font-display font-bold text-white mb-6 tracking-tighter">
              Dive into the <br/>
              <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-400 to-pink-400">Weird Web</span>
            </h1>
            <p className="text-xl text-slate-400 mb-10 leading-relaxed max-w-2xl mx-auto">
              Break free from the algorithm. Discover curated, obscure, and delightful websites curated by specialized AI models.
            </p>

            <div className="flex flex-col sm:flex-row gap-4 justify-center items-center mb-12">
              <button 
                onClick={handleStumble}
                className="group relative inline-flex items-center gap-3 bg-white text-slate-900 font-bold py-4 px-8 rounded-xl text-xl hover:bg-indigo-50 transition-all transform hover:-translate-y-1 shadow-2xl shadow-indigo-500/30 w-full sm:w-auto justify-center"
              >
                <Sparkles className="text-indigo-600 group-hover:rotate-12 transition-transform" />
                Start Stumbling
              </button>
            </div>

            {/* Collections */}
            <div className="bg-slate-900/40 backdrop-blur rounded-2xl border border-slate-800 p-6">
              <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-4">Curated Collections</h3>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                {COLLECTIONS.map(col => (
                  <button 
                    key={col.id}
                    onClick={() => handleSearch(undefined, col.query)}
                    className="flex flex-col items-center gap-2 p-4 rounded-xl bg-slate-800/50 hover:bg-indigo-600 hover:text-white transition-all border border-slate-700 hover:border-indigo-500 group"
                  >
                    <col.icon size={24} className="text-indigo-400 group-hover:text-white transition-colors mb-1" />
                    <span className="font-bold text-sm">{col.label}</span>
                  </button>
                ))}
              </div>
            </div>

            <div className="mt-8 text-slate-600 text-xs flex gap-4 justify-center items-center">
                 <span>Persona: <span className="text-indigo-400 font-mono">{activePersona.name}</span></span>
                 <span>Model: <span className="text-indigo-400 font-mono">{activeModel.name}</span></span>
            </div>
          </div>
        ) : (
          <div className="w-full max-w-4xl z-10 animate-fade-in min-h-[500px] flex items-center justify-center">
            {status === 'loading' ? (
              <div className="text-center">
                 <div className="w-16 h-16 border-4 border-indigo-500/30 border-t-indigo-500 rounded-full animate-spin mx-auto mb-4"></div>
                 <p className="text-slate-400 font-display animate-pulse text-lg tracking-widest uppercase">
                    {activeModel.name} PROCESSING...
                 </p>
                 {activeModel.supportsThinking && thinkingBudget > 0 && (
                     <p className="text-xs text-indigo-400 mt-2 font-mono">THINKING BUDGET: {thinkingBudget}</p>
                 )}
                 {selectedTag && <p className="text-xs text-slate-500 mt-2">Target: #{selectedTag}</p>}
                 {isSearchActive && <p className="text-xs text-slate-500 mt-2 font-mono">{searchQuery.toUpperCase()}</p>}
              </div>
            ) : currentSite ? (
              <div className="w-full">
                 {isSearchActive && (
                    <div className="flex justify-center mb-4">
                        <span className="bg-indigo-900/50 text-indigo-200 border border-indigo-500/30 px-3 py-1 rounded-full text-xs font-medium flex items-center gap-2">
                            <Search size={12} /> Results for: "{searchQuery}"
                            <button onClick={() => { setIsSearchActive(false); setSearchQuery(''); handleStumble(); }} className="hover:text-white"><X size={12}/></button>
                        </span>
                    </div>
                 )}
                 <SiteCard 
                    site={currentSite} 
                    isFavorite={favorites.some(f => f.id === currentSite.id)}
                    onToggleFavorite={(s) => { playSound('blip'); toggleFavorite(s); }}
                    onVisit={() => window.open(currentSite.url, '_blank')}
                    onTagClick={handleTagClick}
                    onFindSimilar={handleFindSimilar}
                    onAnalyze={handleAnalyzeSite}
                    selectedTag={selectedTag}
                    analysisText={currentAnalysis}
                    isAnalyzing={isAnalyzing}
                 />
              </div>
            ) : (
               <div className="text-center text-slate-500">
                 <AlertCircle size={48} className="mx-auto mb-2 opacity-50" />
                 <p className="mb-4">Signal lost. The weird web is vast, but sometimes empty.</p>
                 <div className="flex gap-4 justify-center">
                    <button onClick={() => { setSelectedTag(null); setSelectedCategory(Category.ALL); setIsSearchActive(false); setSearchQuery(''); playSound('blip'); }} className="text-slate-300 hover:text-white underline">Clear All Filters</button>
                    <button onClick={handleStumble} className="text-indigo-400 hover:underline">Retry</button>
                 </div>
               </div>
            )}
          </div>
        )}

        {/* Mobile Stumble FAB */}
        {!showWelcome && (
          <button 
            onClick={handleStumble}
