export const getSiteAnalysis = async (site: Site, persona: CuratorPersona, model: AIModel, thinkingBudget: number = 0, aesthetic: Aesthetic): Promise<string> => {
    if (!ai) return "AI connection unavailable.";

    const prompt = `
        ${persona.promptModifier}

        TASK: Perform a "Deep Analysis" of this website: ${site.title} (${site.url}).
        CONTEXT: The user is in a ${aesthetic.name} mood.

        Provide a 100-150 word breakdown covering:
        1. Unique features.
        2. Design philosophy.
        3. Cultural significance.
    `;

    const config = getConfig(model, thinkingBudget);
    delete config.responseMimeType;
    delete config.responseSchema;

    try {
        const response = await withRetry<GenerateContentResponse>(() => ai!.models.generateContent({
            model: model.id,
            contents: prompt,
            config: config
        }));

        return response.text || "Analysis failed.";
    } catch (e) {
        console.error(e);
        return "Neural link severed. Analysis unavailable.";
    }
}

