import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { Site, Category, CuratorPersona, AIModel, Aesthetic, TimeEra } from '../types';
import { v4 as uuidv4 } from 'uuid';

const apiKey = process.env.API_KEY || '';

const ai = apiKey ? new GoogleGenAI({ apiKey }) : null;

const withRetry = async <T>(fn: () => Promise<T>, retries = 3, delay = 1000): Promise<T> => {
  try {
    return await fn();
  } catch (error: any) {
    const isQuotaError = error.status === 429 || 
                         error.code === 429 || 
                         error.message?.includes('429') || 
                         error.message?.toLowerCase().includes('quota') ||
                         error.message?.toLowerCase().includes('resource_exhausted');

    if (retries > 0 && isQuotaError) {
      console.warn(`Gemini quota hit. Retrying in ${delay}ms... (${retries} attempts left)`);
      await new Promise(resolve => setTimeout(resolve, delay));
      return withRetry(fn, retries - 1, delay * 2);
    }
    throw error;
  }
};

const parseResponse = (text: string | undefined): Site[] => {
  if (!text) return [];
  try {
    // Attempt to extract JSON from Markdown code blocks
    const jsonMatch = text.match(/```json\s*([\s\S]*?)\s*```/);
    const jsonString = jsonMatch ? jsonMatch[1] : text;

    // Cleanup any remaining markdown artifacts if match failed or wasn't clean
    const cleanText = jsonString.replace(/```json/g, '').replace(/```/g, '').trim();

    const parsedData = JSON.parse(cleanText);

    if (!Array.isArray(parsedData)) {
        console.warn("Parsed data is not an array", parsedData);
        return [];
    }

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    return parsedData.map((item: any) => ({
      ...item,
      id: uuidv4(),
      category: Object.values(Category).includes(item.category) ? item.category : Category.MYSTERY
    }));
  } catch (error) {
    console.error("Failed to parse Gemini response:", error);
    console.debug("Raw text was:", text);
    return [];
  }
};

const getConfig = (model: AIModel, thinkingBudget: number) => {
    // NOTE: 'responseMimeType: "application/json"' is NOT supported when using tools like googleSearch.
    // We must rely on prompt engineering to get JSON output.
    const baseConfig: any = {
        tools: [{ googleSearch: {} }],
    };

    if (model.supportsThinking && thinkingBudget > 0) {
        const budget = Math.min(thinkingBudget, model.maxThinkingBudget || 8192);
        baseConfig.maxOutputTokens = budget + 4096; // Ensure enough room for output after thinking
        baseConfig.thinkingConfig = { thinkingBudget: budget };
    }

    return baseConfig;
};

// --- Main Fetch Function ---
export const fetchRecommendations = async (
    category: Category, 
    persona: CuratorPersona, 
    model: AIModel,
    thinkingBudget: number = 0,
    aesthetic: Aesthetic,
    timeEra: TimeEra,
    count: number = 3
): Promise<Site[]> => {
  if (!ai) return [];

  const categoryPrompt = category === Category.ALL ? "any category" : `the category '${category}'`;

  // Time Travel Logic
  const timeConstraint = timeEra.id === 'all' 
    ? "" 
    : `STRICT CONSTRAINT: Only find websites established between ${timeEra.range}, or websites that perfectly emulate the design aesthetic of that era.`;

  const prompt = `
    ${persona.promptModifier}

    AESTHETIC FILTER: ${aesthetic.promptModifier}
    ${timeConstraint}

    TASK: Find ${count} REAL, EXISTING, and OBSCURE websites in ${categoryPrompt}.

    CRITICAL RULES:
    1. The websites MUST be real and currently online. Use Google Search to verify they exist.
    2. Do NOT invent fake URLs.
    3. Respect the Persona's "vibe" and selection criteria.
    4. Avoid mainstream sites (Reddit, YouTube, Wikipedia, etc.).
    5. OUTPUT FORMAT: Return a valid JSON array inside a \`\`\`json code block.

    Schema for JSON objects:
    {
      "title": "Site Title",
      "url": "https://...",
      "description": "Short description",
      "category": "One of: ${Object.values(Category).join(', ')}",
      "tags": ["tag1", "tag2"],
      "yearEstablished": "YYYY",
      "curatorNote": "Why this fits the persona"
    }
  `;

  const config = getConfig(model, thinkingBudget);
  // Note: We cannot use responseSchema with googleSearch tool

  try {
    const response = await withRetry<GenerateContentResponse>(() => ai!.models.generateContent({
      model: model.id,
      contents: prompt,
      config: config
    }));
    return parseResponse(response.text);
  } catch (error) {
    console.error("Gemini discovery failed:", error);
    return [];
  }
};

